package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

class CSVFormatTest {

    @Test
    void testGetIgnoreHeaderCase_DefaultInstance() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_WithIgnoreHeaderCaseTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreHeaderCase(true);
        assertTrue(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_WithIgnoreHeaderCaseFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreHeaderCase(false);
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_ReflectionChangeFieldTrue() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        Field field = CSVFormat.class.getDeclaredField("ignoreHeaderCase");
        field.setAccessible(true);

        // Remove final modifier from the field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~Modifier.FINAL);

        // Create new instance with ignoreHeaderCase = true
        CSVFormat newFormat = format.withIgnoreHeaderCase(true);

        // Set the field on the new instance
        field.setBoolean(newFormat, true);

        boolean result = newFormat.getIgnoreHeaderCase();
        assertTrue(result);
    }

    @Test
    void testGetIgnoreHeaderCase_ReflectionChangeFieldFalse() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreHeaderCase(true);

        Field field = CSVFormat.class.getDeclaredField("ignoreHeaderCase");
        field.setAccessible(true);

        // Remove final modifier from the field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~Modifier.FINAL);

        // Create new instance with ignoreHeaderCase = false
        CSVFormat newFormat = format.withIgnoreHeaderCase(false);

        // Set the field on the new instance
        field.setBoolean(newFormat, false);

        boolean result = newFormat.getIgnoreHeaderCase();
        assertFalse(result);
    }
}
